import { useEffect, useMemo, useState } from "react";
import { api, getAuthToken } from "../api";

export default function Cart() {
  const [items, setItems] = useState([]);
  const [error, setError] = useState("");
  const [message, setMessage] = useState("");
  const [houseNumber, setHouseNumber] = useState("");
  const [street, setStreet] = useState("");
  const [city, setCity] = useState("");
  const [stateName, setStateName] = useState("");
  const [pincode, setPincode] = useState("");

  const total = useMemo(
    () => items.reduce((sum, item) => sum + item.quantity * item.medicine_detail.price, 0),
    [items]
  );

  const loadCart = async () => {
    if (!getAuthToken()) {
      setError("Please login to view cart.");
      setItems([]);
      return;
    }
    try {
      setError("");
      const res = await api.get("/cart/");
      setItems(res.data);
    } catch (err) {
      setError("Unable to load cart.");
    }
  };

  useEffect(() => {
    loadCart();
  }, []);

  const updateQuantity = async (id, quantity) => {
    try {
      await api.patch(`/cart/${id}/`, { quantity: Number(quantity) });
      loadCart();
    } catch (err) {
      setError("Unable to update quantity.");
    }
  };

  const removeItem = async (id) => {
    try {
      await api.delete(`/cart/${id}/`);
      loadCart();
    } catch (err) {
      setError("Unable to remove item.");
    }
  };

  const placeOrder = async () => {
    try {
      setMessage("");
      setError("");
      if (!items.length) {
        setError("Your cart is empty.");
        return;
      }
      if (!houseNumber.trim() || !street.trim() || !city.trim() || !stateName.trim() || !pincode.trim()) {
        setError("Please fill house number, street, city, state, and pincode.");
        return;
      }
      const deliveryAddress = `${houseNumber.trim()}, ${street.trim()}, ${city.trim()}, ${stateName.trim()} - ${pincode.trim()}`;
      await api.post("/orders/", {
        items: items.map((i) => i.id),
        delivery_address: deliveryAddress,
        house_number: houseNumber.trim(),
        street: street.trim(),
        city: city.trim(),
        state: stateName.trim(),
        pincode: pincode.trim(),
      });
      for (const item of items) {
        await api.delete(`/cart/${item.id}/`);
      }
      setMessage("✓ Order placed successfully!");
      setHouseNumber("");
      setStreet("");
      setCity("");
      setStateName("");
      setPincode("");
      loadCart();
    } catch (err) {
      setError(err.response?.data?.detail || "Unable to place order.");
    }
  };

  return (
    <div className="page">
      <div className="page-header">
        <h1>🛒 Shopping Cart</h1>
        <p>Review your items and checkout</p>
      </div>

      {error && <div className="error-message">{error}</div>}
      {message && <div className="success-message">{message}</div>}

      {items.length === 0 ? (
        <div className="empty-state">
          <div className="empty-icon">🛒</div>
          <h3>Your cart is empty</h3>
          <p>Add some medicines to get started</p>
        </div>
      ) : (
        <div className="cart-container">
          <div className="cart-items">
            {items.map((item) => (
              <div className="cart-item" key={item.id}>
                <div className="cart-item-info">
                  <h3>{item.medicine_detail.name}</h3>
                  <p>Shop: {item.medicine_detail.shop_name}</p>
                  <p className="price">Unit: ₹ {item.medicine_detail.price}</p>
                </div>

                <div className="cart-item-quantity">
                  <button onClick={() => updateQuantity(item.id, item.quantity - 1)}>−</button>
                  <input 
                    type="number" 
                    value={item.quantity} 
                    onChange={(e) => updateQuantity(item.id, e.target.value)}
                    style={{ width: '50px', textAlign: 'center' }}
                  />
                  <button onClick={() => updateQuantity(item.id, item.quantity + 1)}>+</button>
                </div>

                <div className="cart-item-price">
                  <div className="total">₹ {(item.quantity * item.medicine_detail.price).toFixed(2)}</div>
                  <button onClick={() => removeItem(item.id)} className="btn-remove">Remove</button>
                </div>
              </div>
            ))}
          </div>

          <div className="cart-summary">
            <h3>Order Summary</h3>
            <div className="summary-address">
              <label>Delivery Address</label>
              <input
                type="text"
                value={houseNumber}
                onChange={(e) => setHouseNumber(e.target.value)}
                placeholder="House / Flat No."
              />
              <input
                type="text"
                value={street}
                onChange={(e) => setStreet(e.target.value)}
                placeholder="Street / Area"
              />
              <input
                type="text"
                value={city}
                onChange={(e) => setCity(e.target.value)}
                placeholder="City"
              />
              <div className="summary-address-grid">
                <input
                  type="text"
                  value={stateName}
                  onChange={(e) => setStateName(e.target.value)}
                  placeholder="State"
                />
                <input
                  type="text"
                  value={pincode}
                  onChange={(e) => setPincode(e.target.value)}
                  placeholder="Pincode"
                />
              </div>
            </div>
            <div className="summary-row">
              <span>Items ({items.length}):</span>
              <span>₹ {total.toFixed(2)}</span>
            </div>
            <div className="summary-row" style={{marginTop: '20px', paddingTop: '15px', borderTop: '2px solid #2874f0'}}>
              <span style={{fontWeight: '800', fontSize: '18px'}}>Total:</span>
              <span style={{fontWeight: '800', fontSize: '18px', color: '#1aa260'}}>₹ {total.toFixed(2)}</span>
            </div>
            <button onClick={placeOrder} className="btn-action btn-add-cart checkout-btn">
              ✓ Place Order
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
